export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    // CORS headers for public access
    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    };

    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    try {
      // Request context that gets passed to internal workers
      const requestContext = {
        requestId: crypto.randomUUID(),
        timestamp: Date.now(),
        clientIp: request.headers.get('CF-Connecting-IP'),
        userAgent: request.headers.get('User-Agent'),
        country: request.cf?.country || 'unknown',
      };

      // Attach context as headers for internal workers
      const internalHeaders = new Headers(request.headers);
      internalHeaders.set('X-Request-Id', requestContext.requestId);
      internalHeaders.set('X-Client-IP', requestContext.clientIp || '');
      internalHeaders.set('X-Country', requestContext.country);
      internalHeaders.set('X-Gateway-Timestamp', requestContext.timestamp.toString());

      let response;

      // Route to appropriate internal worker via service bindings
      if (path.startsWith('/api/users')) {
        response = await routeToService(env.USER_SERVICE, request, internalHeaders, '/api/users', path);
      } else if (path.startsWith('/api/products')) {
        response = await routeToService(env.PRODUCT_SERVICE, request, internalHeaders, '/api/products', path);
      } else if (path.startsWith('/api/orders')) {
        response = await routeToService(env.ORDER_SERVICE, request, internalHeaders, '/api/orders', path);
      } else if (path.startsWith('/api/notifications')) {
        response = await routeToService(env.NOTIFICATION_SERVICE, request, internalHeaders, '/api/notifications', path);
      } else if (path === '/health') {
        response = await healthCheck(env);
      } else if (path === '/') {
        response = new Response(JSON.stringify({
          service: 'API Gateway',
          version: '1.0.0',
          endpoints: ['/api/users', '/api/products', '/api/orders', '/api/notifications', '/health'],
        }), {
          headers: { 'Content-Type': 'application/json' },
        });
      } else {
        response = new Response(JSON.stringify({
          error: 'Not Found',
          message: `No route matched for ${path}`,
          requestId: requestContext.requestId,
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' },
        });
      }

      // Clone response and add CORS + gateway headers
      const newHeaders = new Headers(response.headers);
      Object.entries(corsHeaders).forEach(([key, value]) => newHeaders.set(key, value));
      newHeaders.set('X-Request-Id', requestContext.requestId);
      newHeaders.set('X-Gateway-Latency', `${Date.now() - requestContext.timestamp}ms`);

      return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers: newHeaders,
      });
    } catch (err) {
      return new Response(JSON.stringify({
        error: 'Internal Gateway Error',
        message: err.message,
      }), {
        status: 502,
        headers: { 'Content-Type': 'application/json', ...corsHeaders },
      });
    }
  },
};

async function routeToService(serviceBinding, originalRequest, headers, prefix, fullPath) {
  if (!serviceBinding) {
    return new Response(JSON.stringify({
      error: 'Service Unavailable',
      message: `Service binding not configured for ${prefix}`,
    }), {
      status: 503,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  // Strip the prefix and build internal URL
  const internalPath = fullPath.substring(prefix.length) || '/';
  const url = new URL(originalRequest.url);
  const internalUrl = new URL(`https://internal-service${internalPath}${url.search}`);

  const internalRequest = new Request(internalUrl.toString(), {
    method: originalRequest.method,
    headers: headers,
    body: originalRequest.method !== 'GET' && originalRequest.method !== 'HEAD'
      ? originalRequest.body
      : undefined,
  });

  return serviceBinding.fetch(internalRequest);
}

async function healthCheck(env) {
  const services = {
    USER_SERVICE: env.USER_SERVICE,
    PRODUCT_SERVICE: env.PRODUCT_SERVICE,
    ORDER_SERVICE: env.ORDER_SERVICE,
    NOTIFICATION_SERVICE: env.NOTIFICATION_SERVICE,
  };

  const checks = {};

  await Promise.all(
    Object.entries(services).map(async ([name, binding]) => {
      if (!binding) {
        checks[name] = { status: 'not_configured' };
        return;
      }
      try {
        const start = Date.now();
        const res = await binding.fetch(new Request('https://internal-service/health'));
        const latency = Date.now() - start;
        const data = await res.json();
        checks[name] = { status: 'healthy', latency: `${latency}ms`, ...data };
      } catch (err) {
        checks[name] = { status: 'unhealthy', error: err.message };
      }
    })
  );

  const allHealthy = Object.values(checks).every(
    (c) => c.status === 'healthy' || c.status === 'not_configured'
  );

  return new Response(JSON.stringify({
    gateway: 'healthy',
    services: checks,
    timestamp: new Date().toISOString(),
  }), {
    status: allHealthy ? 200 : 503,
    headers: { 'Content-Type': 'application/json' },
  });
}

