// ============================================
// Shared: Base Internal Worker Class
// File: shared/base-worker.js
// ============================================

export class BaseInternalWorker {
  constructor(serviceName) {
    this.serviceName = serviceName;
    this.routes = new Map();
  }

  get(path, handler) {
    this.addRoute('GET', path, handler);
  }

  post(path, handler) {
    this.addRoute('POST', path, handler);
  }

  put(path, handler) {
    this.addRoute('PUT', path, handler);
  }

  delete(path, handler) {
    this.addRoute('DELETE', path, handler);
  }

  addRoute(method, path, handler) {
    const key = `${method}:${path}`;
    this.routes.set(key, { method, path, handler, pattern: this.buildPattern(path) });
  }

  buildPattern(path) {
    const regexStr = path
      .replace(/\/:([^/]+)/g, '/(?<$1>[^/]+)')
      .replace(/\//g, '\\/');
    return new RegExp(`^${regexStr}$`);
  }

  async handleRequest(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname === '' ? '/' : url.pathname;
    const method = request.method;

    // Health check endpoint is always available
    if (path === '/health') {
      return this.healthResponse();
    }

    // Try to match route
    for (const [, route] of this.routes) {
      if (route.method !== method) continue;
      const match = path.match(route.pattern);
      if (match) {
        const params = match.groups || {};
        const context = {
          request,
          env,
          ctx,
          params,
          query: Object.fromEntries(url.searchParams),
          requestId: request.headers.get('X-Request-Id') || 'unknown',
          clientIp: request.headers.get('X-Client-IP') || 'unknown',
          country: request.headers.get('X-Country') || 'unknown',
        };

        // Parse JSON body for non-GET requests
        if (method !== 'GET' && method !== 'HEAD') {
          try {
            const contentType = request.headers.get('Content-Type') || '';
            if (contentType.includes('application/json')) {
              context.body = await request.json();
            } else {
              context.body = await request.text();
            }
          } catch {
            context.body = null;
          }
        }

        try {
          const result = await route.handler(context);
          return this.jsonResponse(result.data, result.status || 200);
        } catch (err) {
          return this.errorResponse(err);
        }
      }
    }

    return this.jsonResponse({
      error: 'Not Found',
      message: `${method} ${path} not found in ${this.serviceName}`,
    }, 404);
  }

  healthResponse() {
    return this.jsonResponse({
      service: this.serviceName,
      status: 'healthy',
      timestamp: new Date().toISOString(),
    });
  }

  jsonResponse(data, status = 200) {
    return new Response(JSON.stringify(data), {
      status,
      headers: {
        'Content-Type': 'application/json',
        'X-Service': this.serviceName,
      },
    });
  }

  errorResponse(err) {
    console.error(`[${this.serviceName}] Error:`, err.message, err.stack);
    const status = err.statusCode || 500;
    return this.jsonResponse({
      error: err.name || 'InternalError',
      message: err.message,
      service: this.serviceName,
    }, status);
  }

  createFetchHandler() {
    return {
      fetch: (request, env, ctx) => this.handleRequest(request, env, ctx),
    };
  }
}

export class ServiceError extends Error {
  constructor(message, statusCode = 500) {
    super(message);
    this.name = 'ServiceError';
    this.statusCode = statusCode;
  }
}


