import { BaseInternalWorker, ServiceError } from '../../shared/base-worker.js';

const productService = new BaseInternalWorker('product-service');

// In-memory cache with TTL
class SimpleCache {
  constructor() {
    this.store = new Map();
  }

  get(key) {
    const entry = this.store.get(key);
    if (!entry) return null;
    if (Date.now() > entry.expiry) {
      this.store.delete(key);
      return null;
    }
    return entry.value;
  }

  set(key, value, ttlMs = 60000) {
    this.store.set(key, { value, expiry: Date.now() + ttlMs });
  }

  invalidate(pattern) {
    for (const key of this.store.keys()) {
      if (key.includes(pattern)) this.store.delete(key);
    }
  }
}

const cache = new SimpleCache();

// GET /
productService.get('/', async ({ query, env }) => {
  const category = query.category || 'all';
  const limit = parseInt(query.limit) || 20;
  const offset = parseInt(query.offset) || 0;
  const cacheKey = `products:${category}:${limit}:${offset}`;

  let products = cache.get(cacheKey);
  if (!products) {
    // Simulate fetching products
    products = [
      { id: 'p1', name: 'Widget A', price: 29.99, category: 'widgets', stock: 150 },
      { id: 'p2', name: 'Gadget B', price: 49.99, category: 'gadgets', stock: 75 },
      { id: 'p3', name: 'Widget C', price: 19.99, category: 'widgets', stock: 200 },
      { id: 'p4', name: 'Gizmo D', price: 99.99, category: 'gizmos', stock: 30 },
    ];

    if (category !== 'all') {
      products = products.filter((p) => p.category === category);
    }

    cache.set(cacheKey, products, 30000); // Cache for 30 seconds
  }

  return {
    data: {
      products: products.slice(offset, offset + limit),
      total: products.length,
      category,
    },
  };
});

// GET /:id
productService.get('/:id', async ({ params, env }) => {
  const { id } = params;
  const cacheKey = `product:${id}`;

  let product = cache.get(cacheKey);
  if (!product) {
    // Simulate DB lookup
    const products = {
      p1: { id: 'p1', name: 'Widget A', price: 29.99, category: 'widgets', stock: 150, description: 'A fine widget' },
      p2: { id: 'p2', name: 'Gadget B', price: 49.99, category: 'gadgets', stock: 75, description: 'A great gadget' },
    };

    product = products[id];
    if (!product) throw new ServiceError('Product not found', 404);
    cache.set(cacheKey, product, 60000);
  }

  return { data: { product } };
});

// POST /
productService.post('/', async ({ body, env }) => {
  if (!body || !body.name || body.price == null) {
    throw new ServiceError('Name and price are required', 400);
  }

  const product = {
    id: `p_${crypto.randomUUID().slice(0, 8)}`,
    name: body.name,
    price: parseFloat(body.price),
    category: body.category || 'uncategorized',
    stock: body.stock || 0,
    description: body.description || '',
    createdAt: new Date().toISOString(),
  };

  cache.invalidate('products:');

  return { data: { product }, status: 201 };
});

// PUT /:id/stock
productService.put('/:id/stock', async ({ params, body, env }) => {
  const { id } = params;
  if (!body || body.quantity == null) {
    throw new ServiceError('Quantity is required', 400);
  }

  const operation = body.operation || 'set'; // set, increment, decrement
  const quantity = parseInt(body.quantity);

  // In production, use Durable Objects for atomic stock operations
  const stockUpdate = {
    productId: id,
    operation,
    quantity,
    updatedAt: new Date().toISOString(),
  };

  cache.invalidate(`product:${id}`);
  cache.invalidate('products:');

  return { data: { stockUpdate } };
});

export default productService.createFetchHandler();


