import { BaseInternalWorker, ServiceError } from '../../shared/base-worker.js';

const orderService = new BaseInternalWorker('order-service');

// GET /
orderService.get('/', async ({ query, env }) => {
  const userId = query.userId;
  const status = query.status || 'all';
  const limit = parseInt(query.limit) || 20;

  const orders = [
    { id: 'o1', userId: '1', items: [{ productId: 'p1', quantity: 2, price: 29.99 }], total: 59.98, status: 'completed', createdAt: '2024-03-01' },
    { id: 'o2', userId: '1', items: [{ productId: 'p2', quantity: 1, price: 49.99 }], total: 49.99, status: 'processing', createdAt: '2024-03-10' },
    { id: 'o3', userId: '2', items: [{ productId: 'p1', quantity: 5, price: 29.99 }], total: 149.95, status: 'pending', createdAt: '2024-03-12' },
  ];

  let filtered = orders;
  if (userId) filtered = filtered.filter((o) => o.userId === userId);
  if (status !== 'all') filtered = filtered.filter((o) => o.status === status);

  return {
    data: {
      orders: filtered.slice(0, limit),
      total: filtered.length,
    },
  };
});

// GET /:id
orderService.get('/:id', async ({ params, env }) => {
  const { id } = params;

  const order = {
    id,
    userId: '1',
    items: [
      { productId: 'p1', quantity: 2, price: 29.99, name: 'Widget A' },
    ],
    total: 59.98,
    status: 'processing',
    shippingAddress: { street: '123 Main St', city: 'Example', zip: '12345' },
    createdAt: '2024-03-10T12:00:00Z',
    updatedAt: '2024-03-10T14:30:00Z',
  };

  return { data: { order } };
});

// POST /
orderService.post('/', async ({ body, env, requestId }) => {
  if (!body || !body.userId || !body.items || !body.items.length) {
    throw new ServiceError('userId and items are required', 400);
  }

  // Validate product availability via product service
  if (env.PRODUCT_SERVICE) {
    for (const item of body.items) {
      try {
        const res = await env.PRODUCT_SERVICE.fetch(
          new Request(`https://internal-service/${item.productId}`, {
            headers: { 'X-Request-Id': requestId },
          })
        );
        if (!res.ok) {
          throw new ServiceError(`Product ${item.productId} not found`, 400);
        }
        const { product } = await res.json();
        if (product.stock < item.quantity) {
          throw new ServiceError(`Insufficient stock for ${product.name}. Available: ${product.stock}`, 400);
        }
      } catch (err) {
        if (err instanceof ServiceError) throw err;
        console.error(`Failed to validate product ${item.productId}:`, err.message);
      }
    }
  }

  // Calculate total
  const total = body.items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  const order = {
    id: `o_${crypto.randomUUID().slice(0, 8)}`,
    userId: body.userId,
    items: body.items,
    total: Math.round(total * 100) / 100,
    status: 'pending',
    shippingAddress: body.shippingAddress || null,
    createdAt: new Date().toISOString(),
  };

  // Decrement stock for each product
  if (env.PRODUCT_SERVICE) {
    for (const item of body.items) {
      try {
        await env.PRODUCT_SERVICE.fetch(
          new Request(`https://internal-service/${item.productId}/stock`, {
            method: 'PUT',
            headers: {
              'Content-Type': 'application/json',
              'X-Request-Id': requestId,
            },
            body: JSON.stringify({ operation: 'decrement', quantity: item.quantity }),
          })
        );
      } catch (err) {
        console.error(`Failed to update stock for ${item.productId}:`, err.message);
      }
    }
  }

  // Send order confirmation notification
  if (env.NOTIFICATION_SERVICE) {
    try {
      await env.NOTIFICATION_SERVICE.fetch(new Request('https://internal-service/send', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Request-Id': requestId,
        },
        body: JSON.stringify({
          type: 'order_created',
          userId: order.userId,
          orderId: order.id,
          total: order.total,
          message: `Order ${order.id} created successfully. Total: $${order.total}`,
        }),
      }));
    } catch (err) {
      console.error('Failed to send order notification:', err.message);
    }
  }

  return { data: { order }, status: 201 };
});

// PUT /:id/status
orderService.put('/:id/status', async ({ params, body, env, requestId }) => {
  const { id } = params;
  if (!body || !body.status) {
    throw new ServiceError('Status is required', 400);
  }

  const validStatuses = ['pending', 'processing', 'shipped', 'completed', 'cancelled'];
  if (!validStatuses.includes(body.status)) {
    throw new ServiceError(`Invalid status. Must be one of: ${validStatuses.join(', ')}`, 400);
  }

  const updatedOrder = {
    id,
    status: body.status,
    updatedAt: new Date().toISOString(),
  };

  // Notify user of status change
  if (env.NOTIFICATION_SERVICE) {
    try {
      await env.NOTIFICATION_SERVICE.fetch(new Request('https://internal-service/send', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Request-Id': requestId,
        },
        body: JSON.stringify({
          type: 'order_status_changed',
          orderId: id,
          status: body.status,
          message: `Order ${id} status updated to: ${body.status}`,
        }),
      }));
    } catch (err) {
      console.error('Failed to send status notification:', err.message);
    }
  }

  return { data: { order: updatedOrder } };
});

export default orderService.createFetchHandler();


