// ============================================
// Worker 5: Notification Service (internal)
// File: notification-worker/src/index.js
// ============================================

import { BaseInternalWorker, ServiceError } from '../../shared/base-worker.js';

const notificationService = new BaseInternalWorker('notification-service');

// Notification queue (in production use Queues or Durable Objects)
const notificationLog = [];

// POST /send
notificationService.post('/send', async ({ body, env, requestId }) => {
  if (!body || !body.type || !body.message) {
    throw new ServiceError('type and message are required', 400);
  }

  const notification = {
    id: `n_${crypto.randomUUID().slice(0, 8)}`,
    type: body.type,
    userId: body.userId || null,
    email: body.email || null,
    orderId: body.orderId || null,
    message: body.message,
    channel: body.channel || 'email',
    status: 'queued',
    requestId,
    createdAt: new Date().toISOString(),
  };

  // In production, push to a Queue for async processing
  // await env.NOTIFICATION_QUEUE.send(notification);

  // For demo, we'll process inline
  try {
    await processNotification(notification, env);
    notification.status = 'sent';
  } catch (err) {
    notification.status = 'failed';
    notification.error = err.message;
    console.error('Notification processing failed:', err.message);
  }

  notificationLog.push(notification);
  if (notificationLog.length > 1000) notificationLog.shift();

  // Store in KV for persistence
  // await env.NOTIFICATIONS_KV.put(`notification:${notification.id}`, JSON.stringify(notification), { expirationTtl: 86400 * 7 });

  return { data: { notification }, status: 201 };
});

// POST /send-batch
notificationService.post('/send-batch', async ({ body, env, requestId }) => {
  if (!body || !body.notifications || !Array.isArray(body.notifications)) {
    throw new ServiceError('notifications array is required', 400);
  }

  const results = await Promise.allSettled(
    body.notifications.map(async (notif) => {
      const notification = {
        id: `n_${crypto.randomUUID().slice(0, 8)}`,
        ...notif,
        status: 'queued',
        requestId,
        createdAt: new Date().toISOString(),
      };

      try {
        await processNotification(notification, env);
        notification.status = 'sent';
      } catch (err) {
        notification.status = 'failed';
        notification.error = err.message;
      }

      return notification;
    })
  );

  const notifications = results.map((r) => r.status === 'fulfilled' ? r.value : { status: 'failed', error: r.reason?.message });

  return {
    data: {
      sent: notifications.filter((n) => n.status === 'sent').length,
      failed: notifications.filter((n) => n.status === 'failed').length,
      total: notifications.length,
      notifications,
    },
    status: 201,
  };
});

// GET /
notificationService.get('/', async ({ query }) => {
  const type = query.type;
  const userId = query.userId;
  const limit = parseInt(query.limit) || 50;

  let filtered = [...notificationLog];
  if (type) filtered = filtered.filter((n) => n.type === type);
  if (userId) filtered = filtered.filter((n) => n.userId === userId);

  return {
    data: {
      notifications: filtered.slice(-limit).reverse(),
      total: filtered.length,
    },
  };
});

// GET /:id
notificationService.get('/:id', async ({ params }) => {
  const { id } = params;
  const notification = notificationLog.find((n) => n.id === id);
  if (!notification) {
    throw new ServiceError('Notification not found', 404);
  }
  return { data: { notification } };
});

async function processNotification(notification, env) {
  // Simulate processing based on channel
  switch (notification.channel) {
    case 'email':
      // In production: call email API (SendGrid, SES, etc.)
      console.log(`[EMAIL] To: ${notification.email || notification.userId}, Message: ${notification.message}`);
      break;
    case 'webhook':
      // In production: POST to webhook URL
      if (notification.webhookUrl) {
        // await fetch(notification.webhookUrl, { method: 'POST', body: JSON.stringify(notification) });
      }
      break;
    case 'push':
      console.log(`[PUSH] To: ${notification.userId}, Message: ${notification.message}`);
      break;
    default:
      console.log(`[${notification.channel.toUpperCase()}] ${notification.message}`);
  }
}

export default notificationService.createFetchHandler();


