// ============================================
// Shared: Rate Limiter Middleware (optional enhancement)
// File: shared/rate-limiter.js
// ============================================

export class RateLimiter {
  constructor(env, options = {}) {
    this.env = env;
    this.maxRequests = options.maxRequests || 100;
    this.windowMs = options.windowMs || 60000; // 1 minute
    this.keyPrefix = options.keyPrefix || 'ratelimit';
  }

  async check(key) {
    if (!this.env.RATE_LIMIT_KV) {
      return { allowed: true }; // No KV bound, skip rate limiting
    }

    const fullKey = `${this.keyPrefix}:${key}`;
    const now = Date.now();
    const windowStart = now - this.windowMs;

    const data = await this.env.RATE_LIMIT_KV.get(fullKey, { type: 'json' });
    const requests = data ? data.filter((ts) => ts > windowStart) : [];

    if (requests.length >= this.maxRequests) {
      return {
        allowed: false,
        remaining: 0,
        resetAt: new Date(requests[0] + this.windowMs).toISOString(),
      };
    }

    requests.push(now);
    await this.env.RATE_LIMIT_KV.put(fullKey, JSON.stringify(requests), {
      expirationTtl: Math.ceil(this.windowMs / 1000) + 10,
    });

    return {
      allowed: true,
      remaining: this.maxRequests - requests.length,
    };
  }
}


// ============================================
// Enhanced Gateway with Rate Limiting & Auth
// File: gateway-worker/src/index-enhanced.js
// ============================================

import { RateLimiter } from '../../shared/rate-limiter.js';

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const startTime = Date.now();

    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    };

    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    const requestId = crypto.randomUUID();

    try {
      // Rate limiting
      const rateLimiter = new RateLimiter(env, { maxRequests: 100, windowMs: 60000 });
      const clientIp = request.headers.get('CF-Connecting-IP') || 'unknown';
      const rateCheck = await rateLimiter.check(clientIp);

      if (!rateCheck.allowed) {
        return new Response(JSON.stringify({
          error: 'Too Many Requests',
          retryAfter: rateCheck.resetAt,
          requestId,
        }), {
          status: 429,
          headers: {
            'Content-Type': 'application/json',
            'Retry-After': '60',
            'X-RateLimit-Remaining': '0',
            ...corsHeaders,
          },
        });
      }

      // Authentication middleware (optional per route)
      const authResult = await authenticateRequest(request, env, path);
      if (!authResult.authenticated && requiresAuth(path)) {
        return new Response(JSON.stringify({
          error: 'Unauthorized',
          message: authResult.message || 'Authentication required',
          requestId,
        }), {
          status: 401,
          headers: { 'Content-Type': 'application/json', ...corsHeaders },
        });
      }

      // Build internal headers
      const internalHeaders = new Headers(request.headers);
      internalHeaders.set('X-Request-Id', requestId);
      internalHeaders.set('X-Client-IP', clientIp);
      internalHeaders.set('X-Country', request.cf?.country || 'unknown');
      internalHeaders.set('X-Gateway-Timestamp', startTime.toString());
      if (authResult.userId) {
        internalHeaders.set('X-Authenticated-User', authResult.userId);
        internalHeaders.set('X-User-Role', authResult.role || 'user');
      }

      // Route mapping
      const routeMap = [
        { prefix: '/api/users', service: env.USER_SERVICE },
        { prefix: '/api/products', service: env.PRODUCT_SERVICE },
        { prefix: '/api/orders', service: env.ORDER_SERVICE },
        { prefix: '/api/notifications', service: env.NOTIFICATION_SERVICE },
      ];

      let response;
      const matchedRoute = routeMap.find((r) => path.startsWith(r.prefix));

      if (matchedRoute) {
        response = await routeToService(matchedRoute.service, request, internalHeaders, matchedRoute.prefix, path);
      } else if (path === '/health') {
        response = await healthCheck(env);
      } else if (path === '/') {
        response = new Response(JSON.stringify({
          service: 'API Gateway',
          version: '1.0.0',
          endpoints: routeMap.map((r) => r.prefix),
        }), {
          headers: { 'Content-Type': 'application/json' },
        });
      } else {
        response = new Response(JSON.stringify({
          error: 'Not Found',
          requestId,
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' },
        });
      }

      // Add response headers
      const finalHeaders = new Headers(response.headers);
      Object.entries(corsHeaders).forEach(([k, v]) => finalHeaders.set(k, v));
      finalHeaders.set('X-Request-Id', requestId);
      finalHeaders.set('X-Gateway-Latency', `${Date.now() - startTime}ms`);
      if (rateCheck.remaining != null) {
        finalHeaders.set('X-RateLimit-Remaining', rateCheck.remaining.toString());
      }

      // Log request (async, don't await)
      ctx.waitUntil(logRequest(env, {
        requestId,
        method: request.method,
        path,
        status: response.status,
        latency: Date.now() - startTime,
        clientIp,
        country: request.cf?.country,
        userId: authResult.userId,
      }));

      return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers: finalHeaders,
      });
    } catch (err) {
      return new Response(JSON.stringify({
        error: 'Internal Gateway Error',
        message: err.message,
        requestId,
      }), {
        status: 502,
        headers: { 'Content-Type': 'application/json', ...corsHeaders },
      });
    }
  },
};

function requiresAuth(path) {
  const publicPaths = ['/', '/health', '/api/products'];
  return !publicPaths.some((p) => path === p || (path.startsWith(p + '/') && p !== '/'));
}

async function authenticateRequest(request, env, path) {
  const authHeader = request.headers.get('Authorization');
  if (!authHeader) return { authenticated: false, message: 'No authorization header' };

  const [scheme, token] = authHeader.split(' ');
  if (scheme !== 'Bearer' || !token) {
    return { authenticated: false, message: 'Invalid authorization scheme' };
  }

  try {
    // In production, verify JWT or check token against KV/D1
    // const payload = await verifyJWT(token, env.JWT_SECRET);
    // return { authenticated: true, userId: payload.sub, role: payload.role };

    // Simplified token check for demo
    if (token === 'demo-token') {
      return { authenticated: true, userId: 'demo-user', role: 'admin' };
    }

    return { authenticated: false, message: 'Invalid token' };
  } catch (err) {
    return { authenticated: false, message: 'Token verification failed' };
  }
}

async function routeToService(serviceBinding, originalRequest, headers, prefix, fullPath) {
  if (!serviceBinding) {
    return new Response(JSON.stringify({
      error: 'Service Unavailable',
      message: `Service binding not configured for ${prefix}`,
    }), { status: 503, headers: { 'Content-Type': 'application/json' } });
  }

  const internalPath = fullPath.substring(prefix.length) || '/';
  const url = new URL(originalRequest.url);
  const internalUrl = `https://internal-service${internalPath}${url.search}`;

  return serviceBinding.fetch(new Request(internalUrl, {
    method: originalRequest.method,
    headers,
    body: ['GET', 'HEAD'].includes(originalRequest.method) ? undefined : originalRequest.body,
  }));
}

async function healthCheck(env) {
  const services = { USER_SERVICE: env.USER_SERVICE, PRODUCT_SERVICE: env.PRODUCT_SERVICE, ORDER_SERVICE: env.ORDER_SERVICE, NOTIFICATION_SERVICE: env.NOTIFICATION_SERVICE };
  const checks = {};
  await Promise.all(Object.entries(services).map(async ([name, binding]) => {
    if (!binding) { checks[name] = { status: 'not_configured' }; return; }
    try {
      const start = Date.now();
      const res = await binding.fetch(new Request('https://internal-service/health'));
      checks[name] = { status: 'healthy', latency: `${Date.now() - start}ms`, ...(await res.json()) };
    } catch (err) { checks[name] = { status: 'unhealthy', error: err.message }; }
  }));
  return new Response(JSON.stringify({ gateway: 'healthy', services: checks, timestamp: new Date().toISOString() }), {
    status: Object.values(checks).every((c) => c.status === 'healthy' || c.status === 'not_configured') ? 200 : 503,
    headers: { 'Content-Type': 'application/json' },
  });
}

async function logRequest(env, logEntry) {
  try {
    // Log to Analytics Engine, KV, or external service
    // await env.ANALYTICS.writeDataPoint({ blobs: [JSON.stringify(logEntry)], doubles: [logEntry.latency], indexes: [logEntry.requestId] });
    console.log(`[REQUEST LOG] ${JSON.stringify(logEntry)}`);
  } catch (err) {
    console.error('Failed to log request:', err.message);
  }
}


